ee:variables.ee:set-variable:
%dw 2.0
output application/java
---
{
	mealId: vars.mealId,
	userId: vars.userId,
	mealType: payload.mealType,
	consumedAt: payload.consumedAt as DateTime {
		format: "yyyy-MM-dd'T'HH:mm:ssXXX"
	} as String {
		format: "yyyy-MM-dd HH:mm:ssXXX"
	} default null
}

db:select.db:input-parameters:
#[%dw 2.0
output application/java
---
{
	id : payload.portionId default vars.item_response[0].portion_id
}]
